-- Rabbit Nutrition Database - seed generated from project extraction
-- Version: rabbit_requirements_2026_1_extraction_v1
-- Created: 2026-06-06

DROP TABLE IF EXISTS normalization_notes;
DROP TABLE IF EXISTS do_not_integrate;
DROP TABLE IF EXISTS ingredient_compositions;
DROP TABLE IF EXISTS nutrient_requirements;
DROP TABLE IF EXISTS nutrients;
DROP TABLE IF EXISTS animal_profiles;
DROP TABLE IF EXISTS species;
DROP TABLE IF EXISTS sources;

CREATE TABLE sources (
    id TEXT PRIMARY KEY,
    title TEXT NOT NULL,
    organization TEXT,
    publication_year INTEGER,
    source_type TEXT,
    language TEXT,
    url TEXT,
    reliability_level TEXT,
    use_in_db TEXT,
    notes TEXT
);
CREATE TABLE species (
    id TEXT PRIMARY KEY,
    common_name_fr TEXT,
    common_name_en TEXT,
    scientific_name TEXT
);
CREATE TABLE animal_profiles (
    id TEXT PRIMARY KEY,
    species_id TEXT NOT NULL,
    life_stage TEXT,
    physiological_status TEXT,
    label_fr TEXT,
    description TEXT,
    FOREIGN KEY (species_id) REFERENCES species(id)
);
CREATE TABLE nutrients (
    id TEXT PRIMARY KEY,
    canonical_name TEXT NOT NULL,
    display_name_fr TEXT,
    category TEXT,
    synonyms TEXT
);
CREATE TABLE nutrient_requirements (
    id TEXT PRIMARY KEY,
    species_id TEXT NOT NULL,
    animal_profile_id TEXT NOT NULL,
    nutrient_id TEXT NOT NULL,
    requirement_type TEXT,
    min_value REAL,
    target_value REAL,
    max_value REAL,
    unit TEXT NOT NULL,
    basis TEXT NOT NULL,
    source_id TEXT NOT NULL,
    source_metric TEXT,
    confidence_level TEXT,
    review_status TEXT,
    priority TEXT,
    version TEXT,
    notes TEXT,
    FOREIGN KEY (species_id) REFERENCES species(id),
    FOREIGN KEY (animal_profile_id) REFERENCES animal_profiles(id),
    FOREIGN KEY (nutrient_id) REFERENCES nutrients(id),
    FOREIGN KEY (source_id) REFERENCES sources(id)
);
CREATE TABLE ingredient_compositions (
    id TEXT PRIMARY KEY,
    ingredient_id TEXT,
    ingredient_name_fr TEXT,
    ingredient_name_en TEXT,
    nutrient_id TEXT,
    avg_value REAL,
    sd REAL,
    min_value REAL,
    max_value REAL,
    unit TEXT,
    basis TEXT,
    source_id TEXT,
    use_in_db TEXT,
    notes TEXT,
    FOREIGN KEY (nutrient_id) REFERENCES nutrients(id),
    FOREIGN KEY (source_id) REFERENCES sources(id)
);
CREATE TABLE do_not_integrate (
    nutrient_key TEXT PRIMARY KEY,
    reason TEXT,
    status TEXT
);
CREATE TABLE normalization_notes (
    id TEXT PRIMARY KEY,
    note TEXT
);

