INSERT INTO sources (id, title, organization, publication_year, source_type, language, url, reliability_level, use_in_db, notes) VALUES ('SRC_FEDIAF_2024', 'Nutritional Guidelines for Feeding Pet Rabbits', 'FEDIAF', 2024, 'veterinary_guideline', 'en', 'https://europeanpetfood.org/wp-content/uploads/2025/03/FEDIAF-Nutritional-Guidelines-for-Feeding-Pet-Rabbits-online-version.pdf', 'very_high', 'primary_requirements', 'Main source for rabbit_adult_maintenance numeric nutrient requirements. Values are for total diet at 12% moisture and assumed 10 MJ DE/kg when stated.');
