INSERT INTO sources (id, title, organization, publication_year, source_type, language, url, reliability_level, use_in_db, notes) VALUES ('SRC_CHUV_2025', 'L''alimentation chez le lapin', 'CHUV Universite de Montreal', 2025, 'clinical_fact_sheet', 'fr', 'https://chuv.umontreal.ca/wp-content/uploads/2023/03/Alimentation-lapin-2025.pdf', 'high', 'practical_feeding_rules', 'Francophone clinical source with concrete adult pellet thresholds, greens, water and treat quantities.');
INSERT INTO sources (id, title, organization, publication_year, source_type, language, url, reliability_level, use_in_db, notes) VALUES ('SRC_NCSU_UNDATED', 'Caring for Your Pet Rabbit', 'NCSU Veterinary Hospital', NULL, 'clinical_owner_guide', 'en', 'https://hospital.cvm.ncsu.edu/services/small-animals/nutrition/caring-for-your-pet-rabbit/', 'medium_high', 'practical_feeding_rules', 'Useful for diet fraction, pellet quantity and greens quantity. Mostly owner-facing practical data.');
